mapper.select:
SELECT *
FROM quiz_user
WHERE name = #{name}
  AND phone = #{phone}
LIMIT 1

mapper.update:
UPDATE quiz_history
SET score  = #{score},
    status = #{status}
WHERE history_seq = #{historySeq}

UPDATE quiz_history
SET gift_received_yn = #{giftReceivedYn}
WHERE history_seq = #{historySeq}

mapper.select:
SELECT * FROM quiz_question
WHERE question_id IN

    #{id}

ORDER BY FIELD(question_id,

    #{id}

)

SELECT u.user_seq, u.name, u.phone, u.email, u.region, u.shop_info, u.car_model_code, u.privacy_agree, u.reg_date AS u_reg_date, h.history_seq, h.play_date, h.session_no, h.score, h.status, h.gift_received_yn FROM quiz_user u LEFT JOIN quiz_history h ON u.user_seq = h.user_seq WHERE u.user_seq IN ( SELECT DISTINCT u2.user_seq FROM quiz_user u2 LEFT JOIN quiz_history h2 ON u2.user_seq = h2.user_seq
AND (u2.name LIKE CONCAT('%', #{keyword}, '%') OR u2.phone LIKE CONCAT('%', #{keyword}, '%') OR u2.email LIKE CONCAT('%', #{keyword}, '%'))
AND h2.score = 10
AND h2.play_date = #{searchDate}
AND h2.session_no = #{searchSession}
) ORDER BY h.play_date DESC, h.session_no DESC, u.user_seq DESC
